   884→
   885→const OPTIMIZER_OUTPUT_TYPES = ['PROGRESS', 'HEARTBEAT', 'ERROR', 'RESULT'] as const;
   886→
   887→/**
   888→ * Parse optimizer output message
   889→ */
   890→export function parseOptimizerOutput(
   891→  data: unknown
   892→): { success: true; data: OptimizerOutput } | { success: false; errors: ValidationError[] } {
   893→  if (!data || typeof data !== 'object') {
   894→    return { success: false, errors: [{ field: 'data', message: 'Invalid optimizer output' }] };
   895→  }
   896→
   897→  const d = data as Record<string, unknown>;
   898→  const type = d['type'];
   899→
   900→  if (!OPTIMIZER_OUTPUT_TYPES.includes(type as (typeof OPTIMIZER_OUTPUT_TYPES)[number])) {
   901→    return { success: false, errors: [{ field: 'type', message: 'Invalid optimizer output type' }] };
   902→  }
   903→
   904→  switch (type) {
   905→    case 'PROGRESS':
   906→      return { success: true, data: optimizerProgressSchema.parse(data) as OptimizerProgress };
   907→    case 'HEARTBEAT':
   908→      return { success: true, data: optimizerHeartbeatSchema.parse(data) as OptimizerHeartbeat };
   909→    case 'ERROR':
   910→      return { success: true, data: optimizerErrorSchema.parse(data) as OptimizerError };
   911→    case 'RESULT':
   912→      return { success: true, data: optimizerResultSchema.parse(data) as OptimizerResult };
   913→    default:
   914→      return { success: false, errors: [{ field: 'type', message: 'Unknown output type' }] };
   915→  }
   916→}
